-- Remove duplicate rows keeping one per (name, type, level, state)
DELETE FROM public.schools
WHERE id NOT IN (
  SELECT DISTINCT ON (name, type, level, state) id
  FROM public.schools
  ORDER BY name, type, level, state, id
);

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'schools_name_type_level_state_key') THEN
    ALTER TABLE public.schools ADD CONSTRAINT schools_name_type_level_state_key UNIQUE (name, type, level, state);
  END IF;
END $$;
